const items = $input.all();

return Promise.all(items.map(async (item, index) => {

  const buffer = await this.helpers.getBinaryDataBuffer.call(
    this,
    index,
    'data'
  );

  const base64 = buffer.toString('base64');

  return {
    json: {
      imageBase64: base64
    }
  };
}));

// ── Month mappings ──────────────────────────────────────────────
const TH_MONTHS = {
  "มกราคม": "01", "ม.ค.": "01", "ม.ค": "01",
  "กุมภาพันธ์": "02", "ก.พ.": "02", "ก.พ": "02",
  "มีนาคม": "03", "มี.ค.": "03", "มี.ค": "03",
  "เมษายน": "04", "เม.ย.": "04", "เม.ย": "04",
  "พฤษภาคม": "05", "พ.ค.": "05", "พ.ค": "05",
  "มิถุนายน": "06", "มิ.ย.": "06", "มิ.ย": "06",
  "กรกฎาคม": "07", "ก.ค.": "07", "ก.ค": "07",
  "สิงหาคม": "08", "ส.ค.": "08", "ส.ค": "08",
  "กันยายน": "09", "ก.ย.": "09", "ก.ย": "09",
  "ตุลาคม": "10", "ต.ค.": "10", "ต.ค": "10",
  "พฤศจิกายน": "11", "พ.ย.": "11", "พ.ย": "11",
  "ธันวาคม": "12", "ธ.ค.": "12", "ธ.ค": "12",
};

const EN_MONTHS = {
  "january": "01", "jan": "01", "jan.": "01",
  "february": "02", "feb": "02", "feb.": "02",
  "march": "03", "mar": "03", "mar.": "03",
  "april": "04", "apr": "04", "apr.": "04",
  "may": "05",
  "june": "06", "jun": "06", "jun.": "06",
  "july": "07", "jul": "07", "jul.": "07",
  "august": "08", "aug": "08", "aug.": "08",
  "september": "09", "sep": "09", "sep.": "09",
  "october": "10", "oct": "10", "oct.": "10",
  "november": "11", "nov": "11", "nov.": "11",
  "december": "12", "dec": "12", "dec.": "12",
};

const OCR_MONTH_FIXES = {
  "พ.8.": "พ.ย.", "พ.8": "พ.ย",
  "ม.1.": "ม.ค.", "ม.1": "ม.ค",
  "ก.1.": "ก.ค.", "ก.1": "ก.ค",
  "ก.8.": "ก.ย.", "ก.8": "ก.ย",
  "ส.1.": "ส.ค.", "ส.1": "ส.ค",
  "ต.1.": "ต.ค.", "ต.1": "ต.ค",
  "ธ.1.": "ธ.ค.", "ธ.1": "ธ.ค",
  "มิ.8.": "มิ.ย.", "มิ.8": "มิ.ย",
  "มี.1.": "มี.ค.", "มี.1": "มี.ค",
  "เม.8.": "เม.ย.", "เม.8": "เม.ย",
};

const TH_NAME_PREFIXES = [
  "นาย", "นาง", "นางสาว",
  "น.ส.", "น.ส", "นส.", "นส",
  "ด.ช.", "ด.ช", "ด.ญ.", "ด.ญ",
];
const TH_NAME_PREFIXES_NORMALIZED = {
  "นาย": "นาย", "นาง": "นาง", "นางสาว": "นางสาว",
  "น.ส.": "น.ส.", "น.ส": "น.ส.", "นส.": "น.ส.", "นส": "น.ส.",
  "ด.ช.": "ด.ช.", "ด.ช": "ด.ช.", "ด.ญ.": "ด.ญ.", "ด.ญ": "ด.ญ.",
};

// ── Utilities ───────────────────────────────────────────────────
function escapeRegExp(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function sortedByLenDesc(arr) {
  return [...arr].sort((a, b) => b.length - a.length);
}

// ── Name helpers ────────────────────────────────────────────────
function fixNameEn(name) {
  if (!name) return name;
  name = name.replace(/\bLast\s*name\b/gi, "").trim();
  name = name.replace(/\b(Mr\.|Mrs\.|Miss|Ms\.|Dr\.)(?=\S)/g, "$1 ");
  name = name.replace(/ {2,}/g, " ").trim();
  return name;
}

function fixNameTh(name) {
  if (!name) return name;
  for (const prefix of sortedByLenDesc(TH_NAME_PREFIXES)) {
    if (name.startsWith(prefix)) {
      const normalized = TH_NAME_PREFIXES_NORMALIZED[prefix];
      let rest = name.slice(prefix.length);
      if (rest && !rest.startsWith(" ")) {
        name = normalized + " " + rest;
      }
      break;
    }
  }
  return name.replace(/ {2,}/g, " ").trim();
}

function splitThName(name) {
  const result = { prefix_th: null, first_name_th: null, last_name_th: null };
  if (!name) return result;

  name = fixNameTh(name);
  let rest = name;
  for (const prefix of sortedByLenDesc(TH_NAME_PREFIXES)) {
    const normalized = TH_NAME_PREFIXES_NORMALIZED[prefix];
    if (name.startsWith(normalized)) {
      result.prefix_th = normalized;
      rest = name.slice(normalized.length).trim();
      break;
    }
  }

  const tokens = rest.split(/\s+/).filter(Boolean);
  if (tokens.length) result.first_name_th = tokens[0] || null;
  if (tokens.length > 1) result.last_name_th = tokens.slice(1).join(" ") || null;

  return result;
}

function splitEnName(name) {
  const result = { prefix_en: null, first_name_en: null, last_name_en: null };
  if (!name) return result;

  name = fixNameEn(name);
  let rest = name;
  const match = name.match(/^(Mr\.|Mrs\.|Miss|Ms\.|Dr\.)\s+(.*)$/i);
  if (match) {
    result.prefix_en = match[1];
    rest = match[2].trim();
  }

  const tokens = rest.split(/\s+/).filter(Boolean);
  if (tokens.length) result.first_name_en = tokens[0] || null;
  if (tokens.length > 1) result.last_name_en = tokens.slice(1).join(" ") || null;

  return result;
}

// ── Date helpers ────────────────────────────────────────────────
function fixOcrMonth(text) {
  for (const [wrong, right] of Object.entries(OCR_MONTH_FIXES)) {
    if (text.includes(wrong)) {
      text = text.split(wrong).join(right);
    }
  }
  return text;
}

const TH_MONTH_ALT = sortedByLenDesc(Object.keys(TH_MONTHS)).map(escapeRegExp).join("|");
const TH_DATE_RE = new RegExp(`(\\d{1,2})\\s*(${TH_MONTH_ALT})\\s*(\\d{2,4})`);

const EN_MONTH_ALT = sortedByLenDesc(Object.keys(EN_MONTHS)).map(escapeRegExp).join("|");
const EN_DATE_RE = new RegExp(`(\\d{1,2})\\s*(${EN_MONTH_ALT})\\.?,?\\s*(\\d{2,4})`, "i");

function parseThaiDate(text) {
  text = fixOcrMonth(text.trim());

  let m = TH_DATE_RE.exec(text);
  if (m) {
    const day = m[1].padStart(2, "0");
    const mm = TH_MONTHS[m[2]];
    let yearBe = parseInt(m[3], 10);
    if (yearBe < 100) yearBe += 2500;
    const yearCe = yearBe > 2400 ? yearBe - 543 : yearBe;
    return `${day}/${mm}/${yearCe}`;
  }

  m = EN_DATE_RE.exec(text);
  if (m) {
    const day = m[1].padStart(2, "0");
    const mm = EN_MONTHS[m[2].toLowerCase()];
    let year = parseInt(m[3], 10);
    if (year < 100) year += year > 50 ? 1900 : 2000;
    return `${day}/${mm}/${year}`;
  }

  return "";
}

// ── Window / keyword extraction ────────────────────────────────
function windowFrom(text, startIdx, stopKeywords = [], maxLen = 80) {
  let segment = text.slice(startIdx, startIdx + maxLen);
  let cut = segment.length;
  for (const sk of stopKeywords) {
    const pos = segment.indexOf(sk);
    if (pos !== -1) cut = Math.min(cut, pos);
  }
  segment = segment.slice(0, cut);
  segment = segment.replace(/\s+/g, " ").trim();
  return segment || null;
}

function extractAfterKeyword(text, keyword, stopKeywords = [], maxLen = 80) {
  const idx = text.indexOf(keyword);
  if (idx === -1) return null;
  return windowFrom(text, idx + keyword.length, stopKeywords, maxLen);
}

// ── ID number ───────────────────────────────────────────────────
function extractIdNumber(texts) {
  const combined = texts.join(" ");
  const clean = combined.replace(/[^0-9\s]/g, " ");

  let m = clean.match(/\b(\d\s?\d{4}\s?\d{5}\s?\d{2}\s?\d)\b/);
  if (m) return m[1].replace(/\s/g, "");

  const digitsOnly = clean.replace(/\s+/g, "");
  m = digitsOnly.match(/(\d{13})/);
  if (m) return m[1];

  for (const text of texts) {
    const d = text.replace(/[^0-9]/g, "");
    if (d.length === 13) return d;
  }

  return "";
}

// ── Date-near-keyword search ────────────────────────────────────
function findDateNearKeyword(text, keywords, window = 40) {
  const lower = text.toLowerCase();
  for (const kw of keywords) {
    const kwLower = kw.toLowerCase();
    let searchStart = 0;
    while (true) {
      const idx = lower.indexOf(kwLower, searchStart);
      if (idx === -1) break;
      const segment = text.slice(idx, idx + kw.length + window);
      const found = parseThaiDate(segment);
      if (found) return found;
      searchStart = idx + kw.length;
    }
  }
  return "";
}

function findDateRawAndParsed(text, keywords, pattern, window = 40) {
  const lower = text.toLowerCase();
  for (const kw of keywords) {
    const kwLower = kw.toLowerCase();
    let searchStart = 0;
    while (true) {
      const idx = lower.indexOf(kwLower, searchStart);
      if (idx === -1) break;
      const segment = text.slice(idx, idx + kw.length + window);
      const m = pattern.exec(fixOcrMonth(segment));
      if (m) {
        const raw = m[0].trim();
        const parsed = parseThaiDate(raw);
        if (parsed) return [raw, parsed];
      }
      searchStart = idx + kw.length;
    }
  }
  return ["", ""];
}

function fixDatesInResult(result, rawText) {
  const dateFields = {
    date_of_issue: ["วันออกบัตร", "Date of Issue"],
    date_of_expiry: ["วันบัตรหมดอายุ", "วันหมดอายุ", "Date of Expiry"],
  };

  for (const [field, keywords] of Object.entries(dateFields)) {
    const val = result[field];
    if (val && /^\d{2}\/\d{2}\/\d{4}$/.test(String(val))) continue;

    const found = findDateNearKeyword(rawText, keywords);
    if (found) result[field] = found;
  }

  return result;
}

// ── Address ─────────────────────────────────────────────────────
const ADDRESS_PART_PATTERNS = {
  tambon: /(?:ต\.|ตำบล|แขวง)\s*(\S+)/,
  amphoe: /(?:อ\.|อำเภอ|เขต)\s*(\S+)/,
  province: /(?:จ\.|จังหวัด)\s*(\S+)/,
};

function extractAddressParts(address) {
  const result = { tambon: null, amphoe: null, province: null };
  if (!address) return result;

  for (const [key, pattern] of Object.entries(ADDRESS_PART_PATTERNS)) {
    const m = pattern.exec(address);
    if (m) result[key] = m[1].trim();
  }

  if (!result.province && address.includes("กรุงเทพมหานคร")) {
    result.province = "กรุงเทพมหานคร";
  }

  return result;
}

// ── Birthdate ───────────────────────────────────────────────────
function extractBirthdateInfo(rawText) {
  const [thRaw, thParsed] = findDateRawAndParsed(rawText, ["เกิดวันที่", "วันเกิด"], TH_DATE_RE);
  const [enRaw, enParsed] = findDateRawAndParsed(rawText, ["Date of Birth", "Birth"], EN_DATE_RE);

  let match = null;
  if (thParsed && enParsed) match = thParsed === enParsed;

  return {
    date_of_birth_th: thRaw || null,
    date_of_birth_en: enRaw || null,
    date_of_birth: thParsed || enParsed || null,
    date_of_birth_match: match,
  };
}

// ── Main field extraction ───────────────────────────────────────
function extractFieldsRuleBased(rawText) {
  const rawLines = rawText.split("\n").map(l => l.trim()).filter(Boolean);

  let result = {
    id_number: null,
    prefix_th: null,
    first_name_th: null,
    last_name_th: null,
    prefix_en: null,
    first_name_en: null,
    last_name_en: null,
    date_of_birth_th: null,
    date_of_birth_en: null,
    date_of_birth: null,
    date_of_birth_match: null,
    religion: null,
    address: null,
    tambon: null,
    amphoe: null,
    province: null,
    date_of_issue: null,
    date_of_expiry: null,
  };

  // ID number
  result.id_number = extractIdNumber(rawLines) || null;

  // Thai name
  let nameThRaw = extractAfterKeyword(rawText, "ชื่อตัวและชื่อสกุล", ["Name"], 60);
  if (!nameThRaw) {
    for (const prefix of sortedByLenDesc(TH_NAME_PREFIXES)) {
      const idx = rawText.indexOf(prefix);
      if (idx !== -1) {
        nameThRaw = windowFrom(rawText, idx, ["Name"], 60);
        break;
      }
    }
  }
  Object.assign(result, splitThName(nameThRaw));

  // English name
  const nameEnRaw = extractAfterKeyword(rawText, "Name", ["เกิดวันที่", "Date of Birth"], 60);
  Object.assign(result, splitEnName(nameEnRaw));

  // Religion
  result.religion = extractAfterKeyword(rawText, "ศาสนา", ["ที่อยู่"], 30);

  // Address
  result.address = extractAfterKeyword(rawText, "ที่อยู่", ["วันออกบัตร", "Date of Issue"], 200);

  // Address parts
  Object.assign(result, extractAddressParts(result.address));

  // Birthdate
  Object.assign(result, extractBirthdateInfo(rawText));

  // Issue / expiry dates
  result = fixDatesInResult(result, rawText);

  // Trim all string values
  for (const k of Object.keys(result)) {
    if (typeof result[k] === "string") result[k] = result[k].trim();
  }

  return result;
}

// ── n8n entry point ─────────────────────────────────────────────
const items = $input.all();

return items.map((item) => {
  const rawText = item.json?.message?.content || "";

  let fields;
  try {
    fields = extractFieldsRuleBased(rawText);
  } catch (e) {
    fields = { _error: `Field extraction failed: ${e.message}` };
  }

  fields.raw_ocr_text = rawText;

  return { json: fields };
});

const fs = require('fs');
const path = require('path');

for (const item of $input.all()) {
  const dir = 'C:/Users/jakgh/.n8n-files/ids/' + $now.toFormat('yyyy-MM-dd') + '/';
  const oldPath = dir + item.json.fileName;
  const ext = path.extname(item.json.fileName);
  const base = path.basename(item.json.fileName, ext);
  const newPath = dir + base + '_processed' + ext;

  fs.renameSync(oldPath, newPath);
  item.json.fileName = base + '_processed' + ext;
  item.json.filePath = newPath;
}

return $input.all();

const items = $input.all();
const merged = new Map();

for (const item of items) {
  const data = item.json;
  const id = data.id_number;

  if (!id || (typeof id === "string" && id.trim() === "")) continue;

  if (!merged.has(id)) {
    // structuredClone fallback in case sandbox doesn't expose it
    const clone = typeof structuredClone === "function"
      ? structuredClone(data)
      : JSON.parse(JSON.stringify(data));
    merged.set(id, clone);
    continue;
  }

  const existing = merged.get(id);
  for (const [key, value] of Object.entries(data)) {
    if (
      (existing[key] === null ||
       existing[key] === undefined ||
       existing[key] === "") &&
      value !== null &&
      value !== undefined &&
      value !== ""
    ) {
      existing[key] = value;
    }
  }
}

const result = Array.from(merged.values()).map(json => ({ json }));

// Safety net: if nothing merged, return diagnostic info instead of empty array
if (result.length === 0) {
  return [{
    json: {
      _debug: true,
      inputCount: items.length,
      sampleKeys: items[0] ? Object.keys(items[0].json) : [],
      sampleItem: items[0]?.json ?? null
    }
  }];
}

return result;
